// Simple program in KannadaScript
ಇನ್ಪುಟ್ name = "ಕನ್ನಡಿಗ";
ಮುದ್ರಿಸು("ನಮಸ್ಕಾರ " + name + "!");

ಸಂಖ್ಯೆ a = 10;
ಸಂಖ್ಯೆ b = 20;
ಸಂಖ್ಯೆ sum = a + b;
ಮುದ್ರಿಸು("ಮೊತ್ತ: " + sum);

students = {}
students["Alice"] = [85, 90, 88]
students["Bob"] = [78, 82, 80]
for name, grades in students.items():
    avg = sum(grades)/len(grades)
    print(f"{name}: {avg:.1f}")

function calculate() {
    let num1 = prompt("First number:");
    let num2 = prompt("Second number:");
    let result = Number(num1) + Number(num2);
    alert("Sum: " + result);
}
calculate();

@WebServlet("/users")
public class UserServlet extends HttpServlet {
    protected void doGet(HttpServletRequest req, HttpServletResponse res) {
        req.getRequestDispatcher("/users.jsp").forward(req, res);
    }
}

public class HelloServlet extends HttpServlet {
    protected void doGet(HttpServletRequest req, HttpServletResponse res) {
        res.getWriter().println("Hello from Java EE!");
    }
}

@Entity
@Table(name="products")
public class Product {
    @Id
    @GeneratedValue
    private Long id;
    private String name;
    private BigDecimal price;
}

